settings.custom_css:
selector figure.jltma-image-carousel-figure img {
    width: 100%;
    height: 554px;
    object-position: center;
    object-fit: fill;
}

selector .jltma-image-carousel-wrapper {
    padding: 0 !important;
    margin: 0 !important;
}

selector .jltma-arrows {
    width: 98px !important;
    height: 32px !important;
    background: #FFFFFFB3;
    backdrop-filter: blur(20px);
    left: 50% !important
    ;
    transform: translateX(-50%);
    border-radius: 50px;
    align-items: center;
    gap: 12px;
    padding: 10px;
}

selector .jltma-arrows span {
    width: 12px;
    height: 12px;
    border-radius: 999px;
}

selector .jltma-arrows span[aria-current="true"]{
    background-color: #fff !important;
}

@media (max-width: 768px) {

    selector {
        grid-column: span 2 / span 2;
    }
}

@media (max-width: 425px) {
    selector {
        grid-column: span 1 / span 1;
    }
}

selector .jltma-countdown-item {
        backdrop-filter: blur(14px);
    border: 1px solid rgba(255, 255, 255, 0.4);
}
